import{_ as a,o as t,c as b,j as r,a as o,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"瑞莱的冰晶节杖","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/瑞莱的冰晶节杖.md","filePath":"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/瑞莱的冰晶节杖.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/瑞莱的冰晶节杖.md"};function d(p,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"瑞莱的冰晶节杖",tabindex:"-1"},[o("瑞莱的冰晶节杖 "),r("a",{class:"header-anchor",href:"#瑞莱的冰晶节杖","aria-label":'Permalink to "瑞莱的冰晶节杖"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),n('<h1 id="瑞莱的冰晶节杖-1" tabindex="-1">瑞莱的冰晶节杖 <a class="header-anchor" href="#瑞莱的冰晶节杖-1" aria-label="Permalink to &quot;瑞莱的冰晶节杖&quot;">​</a></h1><p>红水晶<br> 500<br> 通明透红的水晶，内里流淌着生命的力量<br> 有人将其提取出来制作成生命药水，<br> 也有人运用对应魔术将水晶摄入体内增强生机<br> 不过最常用的办法还是佩戴于身上<br> 【生命之源】佩戴者获得1点生命值上限</p><p>增幅典籍<br> 1000<br> 魔法师学徒第一本研读的书籍<br> 里面记载了法术的基础<br> 有着良好的导魔性，并且有着优质的魔法防护系统<br> 所以即使是一些资深者也会使用<br> 【增压】该物品作为法器，会为持有者提供2点法术强度，这会占据武器槽</p><p>爆裂魔杖<br> D+500<br> 由约德尔工匠，使用活木，彩虹宝石，以及一些美味的魔法浆果打造<br> 品质值得信赖的同时，也会给使用者带来一个好心情<br> 这个法杖具有3点法术强度<br> 【魔法涌动】<br> 每轮一次，你的魔力消耗减少1点（不能低于1）<br> 【超负荷】你可以以一个自由动作消耗2点魔力来超负荷这把魔杖的魔法咒文<br> 这会使这把武器在这个场景额外提供3点法术强度</p><p>巨人腰带<br> 红水晶+750<br> 比起山丘巨人而言，被人们俗称为“巨魔”（Troll）的森林巨人们通常有着更为高大、健硕的体魄。在符文之地战争期间，大量受到奥术制约的巨魔们都成了专为人类锻造兵器的苦力，正因如此，也导致了当时野生巨魔数量的锐减。就连遍布于瓦洛兰大陆的探险队也无从寻起巨魔们的踪迹了。久而久之，这件充斥着野兽气息的巨人腰带渐渐成为了一个没落种族的象征，而它为穿戴者所提供的愈合能力更是为人啧啧称奇。然而由于这条腰带的尺寸巨大到了需要三名成年男子才能勉强撑起的地步，所以，拆下其主要部分并佩戴，才是它唯一的用途。<br> 【生命之源】佩戴者改为获得2点生命值上限。</p><p>瑞莱的冰晶节杖<br> 巨人腰带+爆裂魔杖+增幅魔典+C+1000<br> 冰晶节杖为它的操纵者引来蓝心冰川的寒风，将敌人封禁在冰块里。<br> 这个法杖具有11法术强度<br> 【生命之源】持有者获得2点生命值上限。<br> 【寒霜源泉】&quot;当地狱结满冰的时候，我会把它叫做天堂&quot; 持有者的施法攻击改为造成冻寒伤害，且获得【法破】特性。每场景一次，以一个移动动作发动，消耗2点魔力，这把武器在这个场景额外提供3点法术强度，且为持有者提供2点施法鉴定的附加成功。<br> 【活力凝结】“让他们寸步难行！” 每轮一次，你的魔力消耗减少1点（不能低于1），施法攻击附带伤害等量疲乏异常点数（标准豁免）与1点不可豁免的冻结异常点数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(s,[["render",d]]);export{f as __pageData,m as default};
